import React, { Component } from 'react';
import Spinner from 'react-bootstrap/Spinner';

export class FetchData extends Component {
  static displayName = FetchData.name;

  constructor(props) {
    super(props);
    this.state = { data: [], loading: true };
  }

  componentDidMount() {
    this.populateWeatherData();
  }

  static renderForecastsTable(documents) {
    return (
      <table className='table table-striped' aria-labelledby="tabelLabel">
        <tbody>
          {documents.map(document =>
            <tr key={document.datetime}>
              <td>
                <p>{document.datetime}</p>
                <a href="{document.url}" alt="{document.title}"><div dangerouslySetInnerHTML={{ __html: document.title }} /></a>
                <div dangerouslySetInnerHTML={{ __html:document.contents }} />
              </td>
            </tr>
          )}
        </tbody>
      </table>
    );
  }

  render() {
    let contents = this.state.loading ? <div><Spinner animation="border" role="status"><span className="sr-only">Loading...</span></Spinner></div>
                                      : FetchData.renderForecastsTable(this.state.data.documents);

    return (
      <div>
        <h1 id="tabelLabel" >Daum Search</h1>
        <p>https://dapi.kakao.com/v2/search/web</p>
        {contents}
      </div>
    );
  }

  async populateWeatherData() {
    const response = await fetch('/api/kakao/daumSearch/web?query=test');
    const data = await response.json();
    this.setState({ data: data, loading: false });
  }
}
